// Hybrid grader — 3 sub-scores combined.
async function gradeRefund(sample, transcript, toolCalls, fixtureVerdicts) {
  const toolOk    = toolCallVerifier(toolCalls, sample.requiredCalls);
  const outcomeOk = codeExactMatch(transcript.outcome, sample.expectedOutcome);
  const empathy   = fixtureVerdicts[sample.id]; // { score, reasoning }
  const pass = toolOk.pass && outcomeOk && empathy.score >= 0.5;
  return { pass, subs: { toolOk, outcomeOk, empathy }, reasoning: empathy.reasoning };
}
